struct Point { int x, y; };
struct Point3D { int x, y, z; };

void test_target_explicit_map() {
  Point p{1, 2};
  auto [a, b] = p;

#pragma omp target map(tofrom: p)
  {
    a = a + 1;
    b = b + 1;
  }
}

void test_target_implicit_map() {
  Point p{1, 2};
  auto [a, b] = p;

#pragma omp target
  {
    int sum = a + b;
  }
}

void test_target_parallel() {
  Point p{3, 4};
  auto [a, b] = p;

#pragma omp target parallel
  {
    int sum = a + b;
  }
}

void test_target_parallel_for() {
  Point p{5, 6};
  auto [a, b] = p;

#pragma omp target parallel for
  for (int i = 0; i < 10; i++) {
    int result = a + b + i;
  }
}

void test_firstprivate_dsa() {
  Point p{7, 8};
  auto [a, b] = p;

#pragma omp parallel firstprivate(p)
  {
    int sum = a + b;
  }
}

void test_shared_dsa() {
  Point p{9, 10};
  auto [a, b] = p;

#pragma omp parallel shared(p)
  {
    int sum = a + b;
  }
}

void test_reduction_dsa() {
  Point p{1, 2};
  auto [a, b] = p;
  int sum = 0;

#pragma omp parallel for reduction(+:sum)
  for (int i = 0; i < 10; i++) {
    sum += a + b;
  }
}

