template<typename T>
int test_template_bas(T p) {
  auto [a, b] = p;
  int result = 0;

#pragma omp parallel reduction(+:result)
  {
    result = a + b;
  }
  return result;
}

template<typename T>
int test_template_target(T p) {
  auto [a, b] = p;
  int result = 0;

#pragma omp target map(tofrom: result)
  {
    result = a + b;
  }
  return result;
}

template<typename T>
int test_template_task(T p) {
  auto [a, b] = p;
  int result = 0;

#pragma omp task shared(result)
  {
    result = a + b;
  }
#pragma omp taskwait
  return result;
}

template<typename T>
int test_template_3_bindings(T p) {
  auto [x, y, z] = p;
  int result = 0;

#pragma omp parallel reduction(+:result)
  {
    result = x + y + z;
  }
  return result;
}

void instantiate_templates() {
  Point p2{1, 2};
  Point3D p3{1, 2, 3};

  test_template_bas(p2);
  test_template_bas(Point{3, 4});
  test_template_target(p2);
  test_template_task(p2);
  test_template_3_bindings(p3);
}

