void test_lambda_capture_binding_by_value() {
  Point p{10, 20};
  auto [a, b] = p;
  auto lambda = [a]() {
    return a + a;
  };
  int result = lambda();
}


void test_lambda_capture_binding_by_ref() {
  Point p{10, 20};
  auto [a, b] = p;
  auto lambda = [&a]() {
    a = 100;
  };
  lambda();
}


void test_lambda_capture_multiple_bindings() {
  Point p{10, 20};
  auto [a, b] = p;
  auto lambda = [a, &b]() {
    b = a + 50;
  };
  lambda();
}


void test_lambda_implicit_capture() {
  Point p{10, 20};
  auto [a, b] = p;
  auto lambda = [=]() {
    return a + b;
  };
  lambda();
}
